---@class LDreamTripMapData
local LDreamTripMapData = classX("LDreamTripMapData",nil)

function LDreamTripMapData:ctor()
    self.mapRefId = nil

    ---@type V_InsmapRef
    self.mapRef = nil

    ---@type LxInstanceMapObj
    self.insMapObj = nil

    self.index = 1

    self.moveToIndex = nil

    ---@type table<number,LxInstancePointObj>
    self.mapDatas = {}

    --- 记录传送门的平台id
    self._recordPortalGridIdxs = {}

    self.gridCount = 0

    self.execute = DreamTripExecuteState.Default
end

---@param mapRef V_InsmapRef
---@param insMapObj LxInstanceMapObj
function LDreamTripMapData:SetMapData(mapRef,insMapObj)
    self.mapRef = mapRef
    self.mapRefId = mapRef.refId
    self.gridCount = mapRef.gridNum

    self.insMapObj = insMapObj

    if insMapObj.curFinalPoint and insMapObj.curFinalPoint > 0 then
        self.index = insMapObj.curFinalPoint
    else
        self.index = insMapObj.finalPoint
    end
end

function LDreamTripMapData:InitData()
    self:InitMapData()
end

function LDreamTripMapData:InitMapData()
    self.mapDatas = {}
    self._recordPortalGridIdxs = {}

    if not self.insMapObj then return end

    self:UpdateMapDatas()
end

function LDreamTripMapData:SetMoveToIndex(index)
    self.execute = DreamTripExecuteState.Execute
    self.moveToIndex = index
end

function LDreamTripMapData:CheckIsExecute()
    return self.execute == DreamTripExecuteState.Execute
end

function LDreamTripMapData:ResetExecute()
    self.execute = DreamTripExecuteState.Default
end

function LDreamTripMapData:GetMapDatas()
    return self.mapDatas
end

function LDreamTripMapData:GetGridCount()
    return self.gridCount
end

function LDreamTripMapData:SetFinalPoint(index)
    self.index = index
end

--- 获取当前位置
function LDreamTripMapData:GetFinalPoint()
    if self.index > 1 then return self.index end
    if self.index == 1 then return 2 end
    return 1
end

function LDreamTripMapData:CheckIsStart()
    return self.index == 0
end

function LDreamTripMapData:UpdateIndex()
    local moveToIndex = self.moveToIndex or self.index
    self.moveToIndex = nil
    self:SetFinalPoint(moveToIndex)
end

function LDreamTripMapData:GetMapPlayerShowModel()
    local effId = 4503
    if self.mapRef and self.mapRef.playerShow > 0 then
        effId = self.mapRef.playerShow
    end
    local effRef = GameTable.CharacterEffectRef[effId]
    return effRef.model
end

function LDreamTripMapData:UpdateMapDatas()
    self.insMapObj = ModuleCenter.Instance:GetInstanceMapObj(self.mapRefId)
    if not self.insMapObj then return end

    ---@type table<number,V_InsPlatformRef>
    local platformList = CtrlCenter.DreamTrip:GetInsPlatformList(self.mapRefId)
    if not platformList or #platformList < 1 then return end

    local pointObjs = self.insMapObj.pointObjs

    local platformRefIdMap = {}
    for k,v in pairs(pointObjs) do
        platformRefIdMap[v.platformRefId] = v
    end

    ---@type LxInstancePointObj
    local pointObj
    for i,v in ipairs(platformList) do
        if v.eventGroup and v.eventGroup > 0 then
            pointObj = platformRefIdMap[v.refId]
            if pointObj then
                self.mapDatas[v.gridNum] = pointObj
                if CtrlCenter.DreamTrip:CheckIsPortalEvent(pointObj) then
                    table.insert(self._recordPortalGridIdxs,v.gridNum)
                end
            end
        end
    end
end

---@return LxInstancePointObj
function LDreamTripMapData:GetDreamTripMapCurPoint()
    local index = self:GetFinalPoint()
    return self.mapDatas[index]
end

function LDreamTripMapData:CheckCurIndexIsFinish()
    local pointObj = self:GetDreamTripMapCurPoint()
    if not pointObj then return true end
    if CtrlCenter.DreamTrip:CheckIsIgnoreFinishStatus(pointObj) then return true end
    return pointObj.finish
end

function LDreamTripMapData:GetMapRefId()
    return self.mapRefId
end

function LDreamTripMapData:GetMapEditId()
    if self.mapRef then return self.mapRef.mapEditId end
end

function LDreamTripMapData:GetMapBuildShow()
    if not self.mapRef then return end

    return self.mapRef.buildShow
end

function LDreamTripMapData:GetMapBuildSize()
    if not self.mapRef then return 0.6 end

    return self.mapRef.buildSize
end

function LDreamTripMapData:GetPortalTypeGridIndex()
    if #self._recordPortalGridIdxs > 0 then return self._recordPortalGridIdxs[1] end
end

return LDreamTripMapData